INSERT INTO `collection_book` VALUES (7, 834, 'Thẻ Thằn lằn bay', 'Thằn lằn bay dùng cái mỏ dài và cứng để tấn công kẻ thù, đôi khi chúng vẫn dùng để gõ hạt óc chó ăn', 7473, 2, 80, 0, 7, -1, -1, -1, -1, '[{\"param\":1,\"active_card\":0,\"id\":27},{\"param\":3,\"active_card\":1,\"id\":27},{\"param\":5,\"active_card\":2,\"id\":27}]', -1);
INSERT INTO `collection_book` VALUES (8, 835, 'Thẻ Phi long', 'Dùng tốc độ cực nhanh để tiếp cận và hạ gục mục tiêu, Phi long cũng có sở thích hơi lạ là khi bay luôn mở to miệng để đón gió', 7474, 2, 80, 0, 8, -1, -1, -1, -1, '[{\"param\":1,\"active_card\":0,\"id\":28},{\"param\":3,\"active_card\":1,\"id\":28},{\"param\":5,\"active_card\":2,\"id\":28}]', -1);
INSERT INTO `collection_book` VALUES (9, 836, 'Thẻ Quỷ bay', 'Sở trường tấn công chớp choáng kẻ thù, nhưng đâu ai ngờ Quỷ bay lại có bệnh sợ độ cao', 7475, 2, 80, 0, 9, -1, -1, -1, -1, '[{\"param\":5,\"active_card\":0,\"id\":47},{\"param\":10,\"active_card\":1,\"id\":47},{\"param\":15,\"active_card\":2,\"id\":47}]', -1);
INSERT INTO `collection_book` VALUES (10, 837, 'Thẻ Lính độc nhãn', 'Người ta nuôi quân lính dùng trong 1 giờ, Lính độc nhãn thì không dùng được 5 phút', 7476, 3, 60, 0, 34, -1, -1, -1, -1, '[{\"param\":30,\"active_card\":0,\"id\":7},{\"param\":5,\"active_card\":1,\"id\":0},{\"param\":50,\"active_card\":2,\"id\":6}]', -1);
