INSERT INTO `collection_book` VALUES (12, 839, 'Thẻ Sói xám', 'Được lính độc nhãn thuần hóa và cho giữ nhà như cún con, sở thích của chúng là được chơi trò nhặt bóng', 7478, 3, 60, 0, 36, -1, -1, -1, -1, '[{\"param\":5,\"active_card\":0,\"id\":0},{\"param\":30,\"active_card\":1,\"id\":7},{\"param\":50,\"active_card\":2,\"id\":6}]', -1);
INSERT INTO `collection_book` VALUES (13, 840, 'Thẻ Trung úy Trắng', 'Thân hình hơi béo so với tiêu chuẩn chung, luôn đeo chiếc khăn quàng đỏ, thường hay mơ mộng làm thơ', 7480, 4, 40, 1, -1, 141, 142, 143, -1, '[{\"param\":15,\"active_card\":0,\"id\":47},{\"param\":15,\"active_card\":1,\"id\":0},{\"param\":50,\"active_card\":2,\"id\":47},{\"param\":100,\"active_card\":3,\"id\":47},{\"param\":200,\"active_card\":4,\"id\":47}]', -1);
INSERT INTO `collection_book` VALUES (14, 841, 'Thẻ Ninja Áo Tím', 'Ninja với nhiều tài năng để trở thành sát thủ, nhưng kỹ thuật ẩn thân lại không có, nên không thể trở thành sát thủ', 7481, 4, 40, 1, -1, 123, 124, 125, -1, '[{\"param\":100,\"active_card\":0,\"id\":7},{\"param\":1,\"active_card\":1,\"id\":114},{\"param\":1,\"active_card\":2,\"id\":114},{\"param\":1,\"active_card\":3,\"id\":114},{\"param\":1,\"active_card\":4,\"id\":114}]', -1);
