INSERT INTO `collection_book` VALUES (16, 859, 'Thẻ Độc Nhãn', 'Đầu não của Red Ribbon. Bị chột một mắt. Lúc nhỏ bị mọi người chê là \'Thằng lùn\'', 1568, 5, 40, 1, -1, 144, 145, 146, -1, '[{\"param\":1,\"active_card\":0,\"id\":175},{\"param\":2,\"active_card\":1,\"id\":175},{\"param\":3,\"active_card\":2,\"id\":175},{\"param\":3,\"active_card\":3,\"id\":175},{\"param\":3,\"active_card\":4,\"id\":175}]', -1);
