INSERT INTO `notifications` VALUES (1, 'NỘI DUNG SỰ KiỆN HÈ 2023', 'Chào các cư dân:\r\n\r\n- Admin sẽ tiến hành bảo trì để update nội dung sự kiện hè\r\n\r\nPHÁ TAN CƠN NÓNG MÙA HÈ\r\n\r\nThời gian: 00h00 19/06 đến 23h59 18/07\r\n\r\nHoạt động hè bao gồm các nội dung sau:\r\n​1/ Tắm nước nóng:\r\n- Tắm nước nóng là giải pháp giúp các cư dân thư giãn sau những ngày học tập, làm việc mệt nhọc.\r\n- Các cư dân sẽ tiến hành đánh quái, đánh boss, hoàn thành các phó bản để nhận được cái nguyên liệu cần thiết để chế tạo Bồn Tắm:\r\n- Bồn tắm gỗ\r\n- Bồn tắm vàng\r\n\r\n* Cành Khô:\r\n- Đánh mộc nhân tại làng để nhận được, mỗi ngày nhận tối đa x99 cái.\r\n- Vật phẩm ký gửi vàng.\r\n\r\n* Nước Suối Tinh Khiết:\r\n- Đánh quái ở Kho báu dưới biển, đánh quái ở Đảo Kame. mỗi ngày chỉ nhận tối đa x99 cái.\r\n- Vật phẩm ký gửi vàng.\r\n\r\n* Gỗ Lớn:\r\n- Đánh quái ở hành tình Cool, Khu vực Sông Băng, mỗi ngày nhận tối đa x99 cái.\r\n- Vật phẩm ký gửi vàng.\r\n\r\n* Que Đốt:\r\n- Đánh Boss bất kỳ để nhận, thắng vòng 2 đại hội võ thuật, mỗi ngày chỉ nhận tối đa x10 cái.\r\n- Vật phẩm ký gửi vàng\r\n\r\n- Sau khi tìm đủ nguyên liệu các cư dân sẽ đến Bà Hạt Mít chế tạo Bồn Tắm:\r\n\r\nCông thức chế tạo:\r\nBồn Tắm Gỗ:\r\nCành khô x50\r\nNước Suối Tinh Khiết x20\r\nGỗ Lớn x20\r\nQue đốt x2\r\nVàng 150,000,000\r\nYêu cầu chỉ được sử dụng trong Làng.\r\nCác cư dân cần phải tắm trong vòng 3 phút sẽ được 1,000 điểm Exp và 1 phần quà ngẫu nhiên trong danh sách quà sau:\r\n- Quạt Ba Tiêu ( Hạn sử dụng )\r\n- Vỏ Ốc ( Hạn sử dụng )\r\n- Cây Kem ( Hạn sử dụng )\r\n- Cá Heo ( Hạn sử dụng )\r\n- Con Diều ( Hạn sử dụng - vĩnh viễn )\r\n- Diều Rồng ( Hạn sử dụng - vĩnh viễn )\r\n- Cải trang Hè 2021 ( Hạn sử dụng - vĩnh viễn )\r\n\r\n(Vật phẩm ký gửi vàng)\r\n\r\nBồn Tắm Vàng:\r\nCành khô x50\r\nNước Suối Tinh Khiết x20\r\nGỗ Lớn x20\r\nQue đốt x2\r\nVàng 300,000,000\r\nNgọc bất kỳ 5\r\nYêu cầu chỉ được sử dụng trong Làng.\r\nCác cư dân cần phải tắm trong vòng 1 phút sẽ được 2,000 điểm Exp và 1 phần quà ngẫu nhiên trong danh sách quà sau:\r\n- Quạt Ba Tiêu ( Hạn sử dụng )\r\n- Vỏ Ốc ( Hạn sử dụng )\r\n- Cây Kem ( Hạn sử dụng )\r\n- Cá Heo ( Hạn sử dụng )\r\n- Con Diều ( Hạn sử dụng - vĩnh viễn )\r\n- Diều Rồng ( Hạn sử dụng - vĩnh viễn )\r\n- Xiên Cá ( Hạn sử dụng - vĩnh viễn )\r\n- Phóng Lợn ( Hạn sử dụng - vĩnh viễn )\r\n- Cải trang mùa hè 2022 ( Hạn sử dụng - vĩnh viễn )\r\n(Vật phẩm ký gửi vàng)\r\n\r\n2/ Săn bắt bọ:\r\nSăn bắt bọ trong những ngày hè là hoạt động vô cùng vui vẻ được di dạo trong những khu rừng và săn tìm các loại bọ khác nhau.\r\nCác loại Bọ chỉ xuất hiện ở những khu vực đầy cây cối, các cư dân sẽ nhận được Bọ khi đánh quái trong khu vực này:\r\n\r\n- Rừng dương xỉ, rừng bambo bắt được Bọ Kiến Vương Hai Sừng, mỗi ngày bắt được x99 bọ.\r\n- Rừng nguyên sinh, rừng thông bắt được Bọ Hung Tê Giác, mỗi ngày bắt được x99 bọ.\r\n- Đồi nấm tím, thung lũng namec bắt được Bọ Kẹp Kìm. mỗi ngày bắt được x99 bọ.\r\n\r\nCách bắt Bọ Cánh Cứng:\r\nBọ cánh cứng vương rất thông minh nên không dễ bắt được chúng, các cư dân cần phải đặt mồi dụ nó ra để tiến hành bắt. Mỗi ngày chỉ bắt được x99 bọ\r\n\r\nSử dụng\r\nBọ Kiến Vương Hai Sừng x10\r\nBọ Hung Tê Giác x10\r\nBọ Kẹp Kìm x10\r\nHũ Mật Ong x1\r\n\r\nNhững khu vực sẽ xuất hiện Bọ Cánh Cứng:\r\nRừng dương xỉ, rừng bambo\r\nRừng nguyên sinh, rừng thông\r\nĐồi nấm tím, thung lũng namec\r\n\r\nHũ Mật Ong được bán ở Santa với giá 200,000,000 vàng\r\n\r\nTặng Bọ Cánh Cứng cho Quy Lão sẽ nhận được 1 phần quà ngẫu nhiên trong danh sách sau:\r\n- Ván Lướt Sóng hạn sử dụng\r\n- Quả Bóng Siêu Việt ( Hạn sử dụng )\r\n- Cây Kem ( Hạn sử dụng )\r\n- Cá Heo ( Hạn sử dụng )\r\n- Con Diều ( Hạn sử dụng - Vĩnh Viễn )\r\n- Diều Rồng ( Hạn sử dụng - Vĩnh Viễn )\r\n- Xiên Cá ( Hạn sử dụng - Vĩnh Viễn )\r\n- Bọ Cánh Cứng (pet) ( Hạn sử dụng - Vĩnh Viễn )\r\n\r\nCách bắt Ngài Đêm:\r\nNgài Đêm rất thích yên tĩnh nên bình thường khó gặp được nó, các cư dân cần phải chuẩn bị đầy đủ dụng cụ để bắt nó, mỗi ngày chỉ bắt được x99 bọ.\r\n\r\nBọ Kiến Vương Hai Sừng x10\r\nBọ Hung Tê Giác x10\r\nBọ Kẹp Kìm x10\r\nHũ Mật Ong x1\r\nVợt Bắt Bọ x1\r\n\r\nNhững khu vực sẽ xuất hiện Ngài Đêm:\r\nRừng dương xỉ, rừng bambo\r\nRừng nguyên sinh, rừng thông\r\nĐồi nấm tím, thung lũng namec\r\n\r\nVợt Bắt Bọ được bán ở Santa, giá 200.000.000 vàng\r\n\r\nTặng Ngài Đêm cho Quy Lão sẽ nhận được 1 phần quà ngẫu nhiên trong danh sách sau:\r\n\r\n- Ván Lướt Sóng ( Hạn sử dụng )\r\n- Quả Bóng Siêu Việt ( Hạn sử dụng )\r\n- Cây Kem ( Hạn sử dụng )\r\n- Cá Heo ( Hạn sử dụng )\r\n- Con Diều ( Hạn sử dụng )\r\n- Diều Rồng hạn ( Hạn sử dụng )\r\n- Xiên Cá hạn ( Hạn sử dụng - Vĩnh Viễn )\r\n- Bong Bóng Heo ( Hạn sử dụng - Vĩnh Viễn )\r\n- Ngài Đêm (pet) ( Hạn sử dụng - Vĩnh Viễn )\r\n- Thú cưỡi Ve Sầu Xên ( Hạn sử dụng - Vĩnh Viễn )\r\n\r\n3/ Tìm vỏ ốc:\r\n- Vào những ngày hè nóng bức, được đi tắm biển là tuyệt vời, trong quá trình tắm biển các cư dân có thể sưu tầm vỏ ốc để đổi quà.\r\n- Trong thời gian diễn ra sự kiện, tại Santa có bán vật phẩm Quần hoa.\r\nKhi mặc vào các cư dân phải cởi áo và cải trang ra (trừ Avatar) đánh quái sẽ có cơ hội nhận được Vỏ ốc, Sò, Cua, Sao biển.\r\n- Tại Santa cũng có bán Trái dừa, khi dùng sẽ có tỉ lệ đánh quái rơi các vật phẩm trên cao hơn (Vỏ ốc, Sò, Cua, Sao biển).\r\n- Tích Vỏ ốc, Sò, Cua, Sao biển và mang đến Quy Lão Kame để đổi quà. Nhiều phần quà hấp dẫn đang chờ đón các cư dân khám phá.\r\n\r\nĐổi quà:\r\n- Vỏ ốc x99 sẽ đổi được 1 món ngẫu nhiên\r\nHoa hồng vàng hạn sử dụng\r\nHoa hồng đỏ hạn sử dụng\r\n\r\n- Sò x99 sẽ đổi được 1 món ngẫu nhiên\r\nPet thỏ mập\r\nPet thỏ ốm\r\n\r\n- Cua x99 sẽ đổi được 1 món ngẫu nhiên\r\nPhượng Hoàng Lửa hạn sử dụng\r\nRùa Phun Lửa hạn sử dụng\r\n\r\n- Sao biển x99 sẽ đổi được 1 món ngẫu nhiên\r\nMảnh áo thiên thứ\r\nMảnh quần thiên sứ\r\nMảnh giày thiên sứ\r\n\r\nDùng:\r\n- Vỏ ốc x99 + Sò x99 + Cua x99 + Sao biển x99 sẽ đổi được Cải trang Mùa Hè 2022 ( Hạn sử dụng - Vĩnh Viễn )\r\n');
INSERT INTO `notifications` VALUES (2, 'CẬP NHẬT TRANG BỊ THIÊN SỨ', '1/CẬP NHẬT TRANG BỊ THIÊN SỨ\r\n- Mảnh găng Rớt từ tất cả loại BOSS\r\n- Mảnh Áo + Quần Rớt tại quái Hành tinh thực vật\r\n- Mảnh giày tại các BOSS trong các phó bản\r\n- Mảnh nhẫn Tại rương 10-11 DHVT 23\r\n\r\n2/ ĐÁ MAY MẮN\r\nGặp ToriBot tại Đảo Kame để có thể mua được vật phẩm\r\nĐá cấp 1 : Tăng 10% tỉ lệ thành công - Mua Max 10/ngày\r\nĐá cấp 2 : Tăng 20% tỉ lệ thành công - Mua Max 10/ngày\r\nĐá cấp 3 : Tăng 30% tỉ lệ thành công - Mua Max 5/ngày\r\nĐá cấp 4 : Tăng 40% tỉ lệ thành công - Mua Max 2/ngày\r\nĐá cấp 5 : Tăng 50% tỉ lệ thành công - Mua Max 1/ngày\r\n(*) CÔNG THỨC BẮT BUỘC ĐỂ CƯỜNG HÓA\r\nCông thức trái đất thường\r\nCông thức Namek thường\r\nCông thức Xayda thường\r\n(*) CÔNG THỨC VIP ĐỂ TĂNG TỈ LỆ CƯỜNG HÓA\r\nCông thức trái đất VIP: Tăng 10% tỉ lệ thành công - Mua Max 10/ngày\r\nCông thức trái đất VIP: Tăng 10% tỉ lệ thành công - Mua Max 10/ngày\r\nCông thức trái đất VIP: Tăng 10% tỉ lệ thành công - Mua Max 10/ngày\r\n\r\n3/ KHI NÂNG CẤP TRANG BỊ THIÊN SỨ\r\n- MUA ĐỒ THIÊn SỨ MẶC ĐỊNH SẼ LÀ ĐỒ TRẮNG\r\n- Với 999 Mảnh + chỉ số mặc định ngẫu nhiên tăng 1-10%\r\nTrang bị xanh dương sẽ có 1 Option Phụ (dễ)\r\nTrang bị Vàng sẽ có 2 Option Phụ (khó)\r\nTrang bị Cam sẽ có 3 Option Phụ (Siêu khó)');
INSERT INTO `notifications` VALUES (5, 'THÔNG BÁO CẬP NHẬT 24/5', 'THÔNG BÁO CẬP NHẬT\r\n\r\n- Pha lê hóa cải trang\r\n- Kí gửi tại siêu thị (đang test)\r\n\r\nChúc các bạn chơi game vui vẻ!!');
